{
  "name": "Fuel Assistance (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross annual household income cannot exceed 60% of Massachusetts' estimated State Median Income for FY 2026. Limits by household size: 1: $51,777; 2: $67,709; 3: $83,641; 4: $99,573; 5: $115,504; 6: $131,436; 7: $127,720-$134,423 (slight source variation); 8: $134,423-$137,410; 9: $137,410; 10: $140,397. Income considered for all household members 18+.[1][3][4][5]",
    "asset_limits": "No asset limits mentioned in program guidelines.[1][4]",
    "other_requirements": ["Reside in Massachusetts.", "Homeowners and renters eligible, including those with heat included in rent.", "Multiple factors beyond income may impact eligibility (e.g., housing subsidies affect benefit level); contact local agency for details.", "For rent-included heat: may need to pay over 30% of income toward rent in some regions."][1][2][4]
  },
  "benefits": {
    "type": "financial",
    "value": "Payments for actual usage or fuel delivery made directly to heating vendor for primary energy needs (oil, electricity, natural gas, propane, kerosene, wood, coal) from November 1 to April 30. Fixed benefit amounts; exact amount varies by factors like housing subsidies, fuel type, and income. Specific benefit levels detailed in FY 2026 LIHEAP Income Eligibility and Benefit Chart.[1][2][3][4]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: HEAP portal at https://toapply.org/MassHEAP (opens October 1 for heating season Nov 1-Apr 30).", "Phone: Call local agency (e.g., Boston/Brookline/Newton: 617.357.6012; Malden/Medford area: 781.322.6284; Cold Relief Heatline: 800.632.8175).", "Mail: To local agency.", "In-person: At local LIHEAP agency (use HEAP portal or lookup tool to find; e.g., Valley Opp Chicopee: 413.552.1548, Holyoke office)."][1][2][3][4]],
    "processing_time": "Not specified; apply early as seasonal (Nov 1-Apr 30, deadline Apr 30).[1][3]",
    "waitlist": null,
    "forms": ["Recertification application (mailed to prior recipients).", "Printable forms available from local providers (e.g., ABCD).", "FY 2026 LIHEAP Income Eligibility and Benefit Chart for reference."][1][3][4]],
    "documents": ["Photo ID for head of household (e.g., driver's license).", "List of all household members.", "Heating bills info (company name, account number).", "Housing info (lease or mortgage statement).", "Proof of income for 30 days prior to application (wages, pension, etc.)."][1][4]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to MA residents.",
    "regional_variations": "Administered by local agencies/providers with potential differences in offices, phone numbers, wait times, and rent-heat subsidy rules (e.g., >30% income to rent in Hampden County). Use HEAP portal or lookup to find local agency by town.[1][2][3][4]",
    "offices_or_providers": ["Local LIHEAP agencies (e.g., Valley Opportunity Council for Hampden County, ABCD for Boston area, Self Help Inc.). Full list via https://www.mass.gov/how-to/apply-for-home-heating-and-energy-assistance or Cold Relief Heatline."][1][2][3]
  },
  "official_source": "https://www.mass.gov/how-to/apply-for-home-heating-and-energy-assistance",
  "gotchas": ["Must apply annually; no automatic renewal.", "Income based on gross annual for all adults 18+; not just head of household.", "Heat-in-rent households may need to prove >30% income to rent and get income subsidy Nov-Apr.", "Benefit level affected by housing subsidies/fuel type; not guaranteed fixed amount.", "Over-income households may qualify for Mass Save Moderate Income program instead (call 1-866-527-7283).", "Seasonal only (Nov 1-Apr 30); apply starting Oct 1."[1][2][3][4][6]],
  "data_shape_notes": "Administered regionally by local agencies with unified statewide income limits at 60% SMI; benefits scale by household size, fuel type, housing status, and local factors; no age or asset test."
}

{
  "name": "SHINE (Serving Health Insurance Needs of Everyone)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Massachusetts residents eligible for Medicare (typically age 65+) or approaching eligibility, their caregivers, and those with limited resources seeking related programs[1][2][3][9]",
    "asset_limits": "No asset limits; no financial tests required for SHINE counseling itself[4][5]",
    "other_requirements": ["Massachusetts resident[1][2][9]", "Eligible for Medicare or approaching Medicare eligibility, or caregiver[2][3][5][9]", "U.S. citizenship or immigration status may apply for screened programs like MassHealth, but not for SHINE counseling[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased health insurance information, counseling, and assistance including: Medicare Parts A/B/C/D, Medigap, Medicare Advantage, prescription drug plans, MassHealth, Medicare Savings Programs (QMB/SLMB/QI), Extra Help/LIS, Prescription Advantage; screening for eligibility and help with applications for cost-saving programs; enrollment process guidance[2][3][4][7][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Call MassOptions at 1-800-243-4636 to find a local SHINE counselor[6][9]", "In-person: At senior centers, Councils on Aging, or Regional Aging Services Access Points[9]", "Phone/email/virtual/mail via local providers (e.g., Mattapoisett: 508-758-4110; regional sites vary)[1][4]", "SHINE staff directory via MassOptions[9]"],
    "processing_time": "Immediate counseling appointment scheduling; no formal processing as it's direct assistance[2][4]",
    "waitlist": "High demand periods like Medicare Open Enrollment may have wait times (e.g., Cape Cod recorded 3,600+ appointments in 2025 season)[2]",
    "forms": ["No specific SHINE form; counselors assist with Medicare, MassHealth, Extra Help, etc. applications[3][4]"],
    "documents": ["Medicare card, current insurance details, income info for program screenings (optional for counseling)[3][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Massachusetts residents only[1][2][9]",
    "regional_variations": "Administered locally via Councils on Aging, elder service agencies, and regional offices (e.g., Barnstable County for Cape Cod & Islands with county funding; high demand varies by area like Cape Cod during enrollment)[2][7][9]",
    "offices_or_providers": ["Local: Councils on Aging, senior centers, AgeSpan, LifePath, Access Care Partners; statewide coordination via Executive Office of Elder Affairs[2][4][8][9]"]
  },
  "official_source": "https://www.mass.gov/info-details/serving-the-health-insurance-needs-of-everyone-shine-program[9]",
  "gotchas": ["Not a direct benefits program—provides counseling only, not financial aid itself[3][5]", "High demand during Medicare Open Enrollment (Oct-Dec) and Advantage Open Enrollment (Jan-Mar) may cause appointment delays[2]", "Contact local sites for availability as statewide phone routes to regional counselors[1][6][9]", "Some sites list as 'Health Information Needs of Elders' but full name is 'Health Insurance Needs of Everyone'—same program[7]"],
  "data_shape_notes": "no income/asset test for counseling; regionally administered with local providers and variable demand; volunteer/staff counselors assist with multiple Medicare-related applications but do not provide direct services or funding"
}

{
  "name": "Meals on Wheels",
  "eligibility": {
    "age": 60,
    "income_limits": "No statewide income limits; some local providers apply means-testing for reduced-price or free meals, but most serve any income level based on need[3][7].",
    "asset_limits": "No asset limits mentioned across sources.",
    "other_requirements": ["Chronically or temporarily homebound and unable to shop, prepare, or obtain at least one nutritious meal per day[1][2][6]", "Physically or emotionally unable to prepare meals, with inadequate family/formal support[1]", "Lack of transportation to stores or senior dining sites[1]", "Spouses and dependents with disabilities may qualify regardless of age[5][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritionally balanced hot lunch delivered weekdays (meets 1/3 of daily requirements, low sodium/fat/sugar); special diets for diabetes/heart disease; daily safety check-in and social contact by driver; serves over 30,000 meals daily statewide[1][7][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) or provider via https://www.mealsonwheelsamerica.org/find-meals-and-services/[2]", "Statewide helpline: 1-800-985-6000[3]", "Local examples: Greater Springfield Senior Services (https://www.gsssi.org/meals-on-wheels)[1]; Meals on Wheels Boston (https://www.mealsonwheelsboston.org/)[6]; South Shore Elder Services (https://sselder.org/mealsonwheels/)[8]; Mass Meals on Wheels agency finder (https://www.massmealsonwheels.org)[7]"],
    "processing_time": "Not specified; contact local provider for assessment[2]",
    "waitlist": "Varies by region and provider; some areas have demand exceeding capacity[2]",
    "forms": ["Application and needs assessment (varies by provider); possible doctor/social worker referral[2]"],
    "documents": ["Proof of age, residency, homebound status; doctor referral if requested; income info for means-tested fees[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must reside in service area of local provider (e.g., Boston city limits for Meals on Wheels Boston[6])",
    "regional_variations": "Administered by local AAAs and providers (e.g., Greater Springfield, South Shore Elder Services, Meals on Wheels Boston); eligibility details, fees, wait times, and delivery schedules differ; some emphasize short-term post-hospital needs[1][6][7][8]",
    "offices_or_providers": ["Local AAAs via https://www.massmealsonwheels.org; examples: Greater Springfield Senior Services, Meals on Wheels Boston, South Shore Elder Services[1][6][7][8]"]
  },
  "official_source": "https://www.massmealsonwheels.org (state network); local AAAs; state regs at https://www.mass.gov/doc/651-cmr-4-the-state-funded-nutrition-program-for-elderly-persons/download[5][7]",
  "gotchas": ["Not a single centralized program—must contact specific local provider for service area, exact eligibility, and availability[2][7]", "Homebound status strictly required; drivers cannot leave meals unattended[1][6]", "Fees may apply based on local means-testing (free for most, low-cost otherwise)[3][8]", "Primarily weekday lunch only; no weekends/holidays typically[6]", "Separate from Medicaid/Mom's Meals (which requires enrollment in those plans)[4]"],
  "data_shape_notes": "Decentralized by local AAAs/providers with no uniform statewide income test or application; eligibility emphasizes homebound need over finances; serves 70,000+ daily via network[3][7]"
}

{
  "name": "Massachusetts Senior Legal Helpline",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits for the helpline itself; eligibility for free attorney representation (via referral) depends on separate Massachusetts civil legal services programs, often requiring low income (e.g., below 125% of federal poverty level in some programs).[1][2][3]",
    "asset_limits": "No asset limits mentioned for the helpline; asset tests may apply to referred free attorney services on a program-by-program basis.",
    "other_requirements": ["Massachusetts resident", "Civil legal issues only (e.g., Social Security/SSI, MassHealth, housing, guardianship, etc.).[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal information, advice, and referrals; assistance completing applications for free attorneys from civil legal services programs (most callers not eligible for free attorney); referrals to reduced-fee or private attorneys; materials via text, email, or mail. Covers civil law areas: Social Security/SSI, veterans benefits, MassHealth, Medicare, consumer issues, public benefits, unemployment, foreclosures, guardianship, power of attorney, bankruptcy, evictions, landlord/tenant, utilities, family law, nursing home issues.[1][2]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-342-5297 (Mon-Fri 9am-12pm, English/Spanish)", "Download brochure/form: https://www.mass.gov/doc/senior-legal-help-line/download.[1][2]"],
    "processing_time": "Immediate phone consultation during hours; attorney eligibility/application handled during call if applicable.",
    "waitlist": null,
    "forms": ["No specific form name; helpline assists with applications to civil legal services programs over the phone.[2]"],
    "documents": ["No documents required for initial helpline call; prepare details of legal issue, income info if seeking free attorney referral.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Massachusetts residents only.",
    "regional_variations": "Operated by Volunteer Lawyers Project of Boston; some listings note specific service areas (e.g., North Shore towns like Amesbury, Lowell), but described as statewide for MA seniors.[1]",
    "offices_or_providers": ["Volunteer Lawyers Project of Boston"]
  },
  "official_source": "https://www.mass.gov/doc/senior-legal-help-line/download",
  "gotchas": ["Most callers not eligible for free attorney—primarily info/referral service; excludes criminal, medical malpractice, workers’ comp, personal injury (contingency basis only); limited hours (9am-12pm); not full representation unless referred and qualified elsewhere; separate from AG Elder Hotline (888-243-5337).[1][2][5]"],
  "data_shape_notes": "no income test for helpline access; free info/referral open to all 60+ MA seniors; attorney services via referral with separate eligibility; phone-only primary access with short daily hours"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; support is free for all eligible residents[2][3][6]",
    "asset_limits": "No asset limits; support is free for all eligible residents[2][3][6]",
    "other_requirements": ["Must reside in a nursing home, rest home, or assisted living facility in Massachusetts[1][2][3][6][8]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigate and resolve complaints related to health, safety, welfare, rights; mediate conflicts; regular facility visits; advocate for systemic changes; educate on rights; assist with facility selection; support resident/family councils; handle issues like abuse, care, discharge, autonomy, dietary, environment[1][3][4][5][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 617-222-7495 (statewide main line to connect to local ombudsman)[2][3][6]", "Website: https://www.mass.gov/orgs/massachusetts-long-term-care-ombudsman-program (for regional contacts)[2][4]", "Local/regional offices: Contact via city/town-aligned agency or host sites (e.g., AgeSpan, Springwell, LifePath, Old Colony Planning)[1][7][8][9]", "In-person: At facilities during regular ombudsman visits or local offices[1][8]"],
    "processing_time": "No formal application or processing; complaints investigated promptly by certified ombudsmen[3][4]",
    "waitlist": null,
    "forms": ["No specific forms required; contact directly to file complaint or seek assistance[3][6]"],
    "documents": ["No documents needed; anyone can file on behalf of resident (confidential unless consent or abuse requires reporting)[3][4][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of nursing homes, rest homes, assisted living facilities across Massachusetts[1][2][3]",
    "regional_variations": "Operates from 17 host sites with 41 paid staff and 199 volunteers covering specific regions/cities/towns; local ombudsmen assigned to facilities (e.g., Springwell for 22-town area, LifePath for its area, Old Colony for its region); contact local via main line or directory[1][4][7][8][9]",
    "offices_or_providers": ["State office: 1 Ashburton, Room 517, Boston[2]", "Regional examples: Old Colony Planning Council[1], AgeSpan[2], Springwell (22 towns)[8], LifePath (e.g., 413-829-9234)[9]"]
  },
  "official_source": "https://www.mass.gov/orgs/massachusetts-long-term-care-ombudsman-program",
  "gotchas": ["Not a regulatory agency; cannot enforce rules but advocates and educates on regulations[5]", "Must already reside in qualifying facility—not for community/home care or pre-admission[1][2][3]", "Complaints can be anonymous/confidential, but identity may be disclosed in abuse cases[4][7]", "Families/loved ones can contact on behalf of resident, but services target facility residents[3][6]", "Not healthcare or financial aid; purely advocacy for rights and issue resolution[5]"],
  "data_shape_notes": "no income/asset test; residency in certified long-term care facility required; regionally delivered via 17 host sites and local volunteers; free immediate advocacy access without application"
}

{
  "name": "Enhanced Community Options Program (ECOP)",
  "eligibility": {
    "age": 60,
    "income_limits": "At or below ASAP income guidelines for individual or couple (specific dollar amounts not detailed in sources; aligns with MassHealth/Frail Elder Waiver standards for low-income elders). Less restrictive than full nursing home eligibility to facilitate enrollment[2][3][4].",
    "asset_limits": "Less restrictive resource requirements than MassHealth-funded nursing home care or Frail Elder Waiver, designed for those in process of asset spend-down; exact limits not specified but clarified allowable by CMS SMD #21-004[3]. What counts and exemptions not detailed.",
    "other_requirements": [
      "Clinically qualifies for MassHealth-funded nursing home level of care (same as Frail Elder Waiver)",
      "Resides in geographical area served by local Aging Services Access Point (ASAP)",
      "Typically ineligible for MassHealth Standard (middle-income program for those not yet qualifying for MassHealth waivers)",
      "Frail elder needing services to avoid/postpone nursing home placement[2][3][4][6]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Higher level of in-home supportive services including personal care (e.g., bathing), homemaking, chore, laundry, home health aide, companion, adult day care, home delivered meals, grocery shopping, transportation, personal emergency response systems; maximum 7.5 hours per week of assistance; providers receive set state funding rate per client, adjusted annually[3][5][6].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact local Aging Services Access Point (ASAP) as single point of entry (e.g., Springwell for their region: springwell.com/service/subsidized-home-care/)[6]",
      "In-home comprehensive assessment by ASAP care manager with nurse consultation[6]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Statewide enrollment cap at 7,322 slots (down from 9,000 as of June prior to 2026); new enrollees waitlisted once cap reached, leading to months-long delays and risk of health decline/nursing home placement[3].",
    "forms": [],
    "documents": [
      "Documents for income verification, clinical/nursing home level assessment, residency proof (exact list not detailed; prepare based on ASAP requirements)"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must reside in geographical area served by local ASAP",
    "regional_variations": "Administered through regional ASAPS with varying providers (e.g., Springwell, Mystic Valley Elder Services, Mass Aging Access); potential differences in wait times, spending thresholds, and access due to enrollment cap and local capacity[3][4][6].",
    "offices_or_providers": [
      "Local Aging Services Access Points (ASAPs) such as Springwell, Mystic Valley Elder Services"
    ]
  },
  "official_source": "https://www.mass.gov (specific ECOP page not directly linked; see Mass.gov doc on state programs[8])",
  "gotchas": [
    "Enrollment cap causes waitlists for new applicants; no impact on current enrollees[3][4]",
    "Recent tightening of eligibility (e.g., higher minimum spend threshold for new enrollees as of Feb 2026 or earlier)[4]",
    "Not for MassHealth Standard, Basic, or HMO recipients; bridges to waivers like Frail Elder while assets are spent down[2][3]",
    "Max 7.5 hours/week limits intensity; directs lower-need to basic home care[3][4][5]",
    "State-funded, cheaper than MassHealth alternatives but capped due to costs[4]"
  ],
  "data_shape_notes": "Administered via regional ASAPS with statewide cap and waitlist; eligibility mirrors Frail Elder Waiver clinically but less restrictive assets/income for spend-down phase; recent 2026 caps and tightened thresholds; max fixed 7.5 hours/week"
}
